#include<bits/stdc++.h>
using namespace std;
int d[1000001];

int find(int x) {
	if (d[x] == x) {
		return x;
	} else {
		return d[x]=find(d[x]);
	}
}
void up(int x, int y) {
	int fx = find(x);
	int fy = find(y);
    d[fx]=fy;
}
int main() {
	int n, m;
	cin >> n >> m ;
	for (int i = 1; i <= n; i++) {

		d[i] = i;
	}
	for (int i = 1; i <= m; i++) {
		int x, y, z; 
		cin >> z;
       cin >> x;
        cin >> y;
		if (z == 1) {

			up(x, y);
		} else {
			if (find(x) == find(y)) {
				cout << "Y" << "\n";
			} else {
				cout << "N" << "\n";
			}
		}
	}
	return 0;
}
